// The two ensures pin both runs of `erase` to identical view():
//   post1_self_@ == pre_self_@.subrange(0, start) + pre_self_@.subrange(end, len)
//   post2_self_@ == pre_self_@.subrange(0, start) + pre_self_@.subrange(end, len)
// z3 fails to line these up across the two runs because the subrange/concat
// terms in each ensures use disjoint instantiation paths. Stage the transitive
// equality of the two views, both as plain `==` and via Seq extensionality
// (`=~=`), so det_erase_equal has the view equality it needs.
assert(
    (post1_self_@ == pre_self_@.subrange(0, start as int) + pre_self_@.subrange(end as int, pre_self_@.len() as int))
    && (post2_self_@ == pre_self_@.subrange(0, start as int) + pre_self_@.subrange(end as int, pre_self_@.len() as int))
    ==> post1_self_@ == post2_self_@
);
assert(
    (post1_self_@ == pre_self_@.subrange(0, start as int) + pre_self_@.subrange(end as int, pre_self_@.len() as int))
    && (post2_self_@ == pre_self_@.subrange(0, start as int) + pre_self_@.subrange(end as int, pre_self_@.len() as int))
    ==> post1_self_@ =~= post2_self_@
);
